#!/bin/bash
docker exec shared-redis-6380 redis-cli -h 192.168.1.50 -p 6380 -n 7 LPUSH agent:frontend:inbox "{\"issue_id\":\"login-flow-debug\",\"from\":\"backend\",\"to\":\"frontend\",\"kind\":\"contract_update\",\"summary\":\"Confirmed backend shapes and EnvelopeInterceptor conflict\",\"details\":{\"routes\":[\"/form/api/v1/auth/login\",\"/form/api/v1/user/status\"],\"files_changed\":[],\"contract_notes\":{\"login\":\"Backend returns { 'success': true, 'data': { 'access_token': '...', 'refresh_token': '...', 'user': {...} } }\",\"user_status\":\"Backend returns { 'success': true, 'data': { 'user': {...} } }\",\"envelope_interceptor_issue\":\"If EnvelopeInterceptor unwraps 'data', the object returned to AuthRemoteSource is the inner data object itself. Thus AuthRemoteSource should access response.user instead of response.data.user\"}},\"next_action_requested\":\"Fix AuthRemoteSource to expect unwrapped data (response.user instead of response.data.user) or remove EnvelopeInterceptor. Then retest the full login/status flow.\",\"timestamp\":\"$(date -u +%Y-%m-%dT%H:%M:%SZ)\"}"

docker exec shared-redis-6380 redis-cli -h 192.168.1.50 -p 6380 -n 7 SET agent:issue:login-flow-debug:state "{\"issue_id\":\"login-flow-debug\",\"status\":\"active\",\"owner\":\"frontend\",\"current_phase\":\"retest\",\"frontend_status\":\"unknown\",\"backend_status\":\"working\",\"latest_frontend_summary\":\"\",\"latest_backend_summary\":\"Sent contract_update message regarding EnvelopeInterceptor\",\"current_blocker\":\"\",\"next_action_for_frontend\":\"Fix data unwrap mismatch and retest full flow\",\"next_action_for_backend\":\"Wait for frontend test results\",\"canonical_routes\":{\"login\":\"/form/api/v1/auth/login\",\"user_status\":\"/form/api/v1/user/status\",\"refresh\":\"/form/api/v1/auth/refresh\",\"logout\":\"/form/api/v1/auth/logout\"},\"auth_contract\":{\"login_response_shape\":\"{success: true, data: {access_token, user}}\",\"status_response_shape\":\"{success: true, data: {user}}\",\"auth_mechanism\":\"Bearer Token via Authorization Header\"},\"last_updated_by\":\"backend\",\"last_updated_at\":\"$(date -u +%Y-%m-%dT%H:%M:%SZ)\"}"

docker exec shared-redis-6380 redis-cli -h 192.168.1.50 -p 6380 -n 7 SET agent:backend:heartbeat "$(date -u +%Y-%m-%dT%H:%M:%SZ)"
